public boolean isSubtype(JSType other) {
    if (!(other instanceof ArrowType)) {
        return false;
    }

    ArrowType that = (ArrowType) other;

    // This is described in Draft 2 of the ES4 spec, Section 3.4.7: Subtyping Function Types.

    // this.returnType <: that.returnType (covariant)
    if (!this.returnType.isSubtype(that.returnType)) {
        return false;
    }

    // that.paramType[i] <: this.paramType[i] (contravariant)
    //
    // If this.paramType[i] is required, then that.paramType[i] is required.
    //
    // In theory, the "required-ness" should work in the other direction as well.
    // In other words, if we have
    //
    // function f(number, number) {}
    // function g(number) {}
    //
    // Then f <: g, but g !< f.
    //
    // So, in this case, g < f, but f !< g
    Node thisParam = parameters.getFirstChild();
    Node thatParam = that.parameters.getFirstChild();
    while (thisParam != null && thatParam != null) {
        JSType thisParamType = thisParam.getJSType();
        JSType thatParamType = thatParam.getJSType();
        if (thisParamType != null) {
            if (thatParamType == null || !thatParamType.isSubtype(thisParamType)) {
                return false;
            }
        } else {
            if (thatParamType != null) {
                return false;
            }
        }

        boolean thisIsVarArgs = thisParam.isVarArgs();
        boolean thatIsVarArgs = thatParam.isVarArgs();

        // "that" can't be a supertype, because it's missing a required argument.
        // NOTE(nicksantos): In our type system, we use {function(...?)} and {function(...NoType)} to to indicate that arity should not be
        // checked. Strictly speaking, this is not a correct formulation, because now a sub-function can required arguments that are var_args
        // in the super-function.
        //
        // So, in this case, g < f, but f !< g
        if (!thisIsVarArgs) {
            thisParam = thisParam.getNext();
        }
        if (!thatIsVarArgs) {
            thatParam = thatParam.getNext();
        }

        // both var_args indicates the end
        if (thisIsVarArgs && thatIsVarArgs) {
            thisParam = null;
            thatParam = null;
        }
    }

    // null checking on the parameters
    if (thisParam != null && thisParam.getJSType() == null) {
        return false;
    }

    // Check if the function has required parameters
    if (parameters.getFirstChild() != null && parameters.getFirstChild().isVarArgs() && !that.parameters.getFirstChild().isVarArgs()) {
        return false;
    }

    // "that" can't be a supertype, because it's missing a required arguement.
    // NOTE(nicksantos): In our type system, we use {function(...?)} and {function(...NoType)} to to indicate that arity should not be
    // checked. Strictly speaking, this is not a correct formulation, because now a sub-function can required arguments that are var_args
    // in the super-function.
    //
    // So, in this case, g < f, but f !< g
    if (thisParam != null) {
        return false;
    }

    return true;
}
